1	<script lang="ts">
2		import { page } from '$app/stores';
3		import { onMount } from 'svelte';
4		import { createClient } from '$lib/gql/client';
5		import { gql } from 'graphql-request';
6	
7		const TREND_QUERY = gql`
8			query ProviderTrend($name: String!, $windowDays: Int!) {
9				providerTrend(name: $name, windowDays: $windowDays) {
10					name
11					kind
12					windowDays
13					ceilingTokens
14					projectedRunOutHours
15					series {
16						bucketStart
17						tokens
18						requests
19					}
20				}
21			}
22		`;
23	
24		interface TrendPoint {
25			bucketStart: string;
26			tokens: number;
27			requests: number;
28		}
29	
30		interface ProviderTrend {
31			name: string;
32			kind: 'ENDPOINT' | 'HARNESS';
33			windowDays: number;
34			ceilingTokens: number | null;
35			projectedRunOutHours: number | null;
36			series: TrendPoint[];
37		}
38	
39		let name = $derived($page.params.name);
40		let trend7 = $state<ProviderTrend | null>(null);
41		let trend30 = $state<ProviderTrend | null>(null);
42		let loading = $state(true);
43		let error = $state<string | null>(null);
44	
45		onMount(async () => {
46			try {
47				const client = createClient();
48				const [r7, r30] = await Promise.all([
49					client.request<{ providerTrend: ProviderTrend | null }>(TREND_QUERY, {
50						name: name,
51						windowDays: 7
52					}),
53					client.request<{ providerTrend: ProviderTrend | null }>(TREND_QUERY, {
54						name: name,
55						windowDays: 30
56					})
57				]);
58				trend7 = r7.providerTrend ?? null;
59				trend30 = r30.providerTrend ?? null;
60			} catch (e) {
61				error = e instanceof Error ? e.message : String(e);
62			} finally {
63				loading = false;
64			}
65		});
66	
67		function maxTokens(series: TrendPoint[], ceiling: number | null): number {
68			let m = 0;
69			for (const p of series) {
70				if (p.tokens > m) m = p.tokens;
71			}
72			if (ceiling != null && ceiling > m) m = ceiling;
73			return m === 0 ? 1 : m;
74		}
75	
76		function barHeight(tokens: number, max: number): string {
77			const pct = Math.round((tokens * 100) / max);
78			return `${Math.max(2, pct)}%`;
79		}
80	
81		function formatHours(hours: number | null): string {
82			if (hours == null) return '—';
83			if (hours < 1) return `${Math.round(hours * 60)}m`;
84			if (hours < 48) return `${hours.toFixed(1)}h`;
85			return `${(hours / 24).toFixed(1)}d`;
86		}
87	
88		function totalTokens(series: TrendPoint[]): number {
89			let sum = 0;
90			for (const p of series) sum += p.tokens;
91			return sum;
92		}
93	
94		function totalRequests(series: TrendPoint[]): number {
95			let sum = 0;
96			for (const p of series) sum += p.requests;
97			return sum;
98		}
99	
100		function formatN(n: number): string {
101			if (n < 1000) return `${n}`;
102			if (n < 1_000_000) return `${(n / 1000).toFixed(1)}k`;
103			return `${(n / 1_000_000).toFixed(2)}M`;
104		}
105	</script>
