269	function isGraphQLEndpoint(input: Parameters<typeof globalThis.fetch>[0]): boolean {
270		if (typeof input === 'string') {
271			return new URL(input, globalThis.location?.href ?? 'http://localhost').pathname === '/graphql';
272		}
273		if (input instanceof URL) {
274			return input.pathname === '/graphql';
275		}
276		return new URL(input.url).pathname === '/graphql';
277	}
278	
279	async function requestBodyText(
280		input: Parameters<typeof globalThis.fetch>[0],
281		init?: Parameters<typeof globalThis.fetch>[1]
282	): Promise<string | null> {
283		if (typeof init?.body === 'string') {
284			return init.body;
285		}
286		if (input instanceof Request) {
287			return input.clone().text();
288		}
289		return null;
290	}
