299	function delegateInputFor(
300		input: Parameters<typeof globalThis.fetch>[0]
301	): Parameters<typeof globalThis.fetch>[0] {
302		if (typeof window === 'undefined' || !isGraphQLEndpoint(input)) {
303			return input;
304		}
305		if (typeof input === 'string' || input instanceof URL) {
306			return '/graphql';
307		}
308		return input;
309	}
