311	function withStaticPreviewFallback(fetchFn?: typeof globalThis.fetch): typeof globalThis.fetch {
312		const delegate = fetchFn ?? globalThis.fetch;
313		return async (input, init) => {
314			const delegateInput = delegateInputFor(input);
315			const response = await delegate(delegateInput, init);
316			if (response.status !== 404 || !isGraphQLEndpoint(input)) {
317				return response;
318			}
319	
320			const bodyText = await requestBodyText(input, init);
321			if (!bodyText) {
322				return response;
323			}
324	
325			let body: { query?: string };
326			try {
327				body = JSON.parse(bodyText) as { query?: string };
328			} catch {
329				return response;
330			}
331	
332			const data = body.query ? fallbackDataForQuery(body.query) : null;
333			return data ? fallbackGraphQLResponse(data) : response;
334		};
335	}
