	resolvedModel: string | null;
	strategy: string | null;
}

interface ProviderModelEntry {
	id: string;
	contextLength: number | null;
	available: boolean;
}

interface ProviderModelsResult {
	name: string;
	kind: 'ENDPOINT' | 'HARNESS';
	baseURL: string;
	fetchedAt: string;
	fromCache: boolean;
	models: ProviderModelEntry[];
}

type ModelsCellState =
	| { phase: 'idle' }
	| { phase: 'loading' }
	| { phase: 'loaded'; result: ProviderModelsResult; expanded: boolean }
	| { phase: 'error'; message: string };

const INLINE_MODEL_LIMIT = 5;

let firstPaintAt = $state<number | null>(null);
let modelsByRow = $state<Record<string, ModelsCellState>>({});
let refreshingRow = $state<Record<string, boolean>>({});

function rowKey(row: { kind: string; name: string }): string {
	return `${row.kind}|${row.name}`;
}

