input.new_string:
async function refresh(client: ReturnType<typeof createClient>) {
	const result = await client.request<{
		providerStatuses: ProviderStatus[];
		harnessStatuses: ProviderStatus[];
	}>(PROVIDER_STATUSES_QUERY);
	rows = [...(result.providerStatuses ?? []), ...(result.harnessStatuses ?? [])];
}

async function loadModelsForRow(
	client: ReturnType<typeof createClient>,
	row: ProviderStatus
): Promise<void> {
	const key = rowKey(row);
	if (modelsByRow[key]?.phase === 'loading' || modelsByRow[key]?.phase === 'loaded') return;
	modelsByRow = { ...modelsByRow, [key]: { phase: 'loading' } };
	try {
		const res = await client.request<{ providerModels: ProviderModelsResult | null }>(
			PROVIDER_MODELS_QUERY,
			{ name: row.name, kind: row.kind }
		);
		if (res.providerModels) {
			modelsByRow = {
				...modelsByRow,
				[key]: { phase: 'loaded', result: res.providerModels, expanded: false }
			};
		} else {
			modelsByRow = {
				...modelsByRow,
				[key]: { phase: 'loaded', result: { name: row.name, kind: row.kind, baseURL: '', fetchedAt: '', fromCache: false, models: [] }, expanded: false }
			};
		}
	} catch (e) {
		modelsByRow = {
			...modelsByRow,
			[key]: { phase: 'error', message: e instanceof Error ? e.message : String(e) }
		};
	}
}

async function refreshModelsForRow(
	client: ReturnType<typeof createClient>,
	row: ProviderStatus
): Promise<void> {
	const key = rowKey(row);
	if (refreshingRow[key]) return;
	refreshingRow = { ...refreshingRow, [key]: true };
	try {
		const res = await client.request<{ refreshProviderModels: ProviderModelsResult }>(
			REFRESH_PROVIDER_MODELS_MUTATION,
			{ name: row.name, kind: row.kind }
		);
		const prevExpanded =
			modelsByRow[key]?.phase === 'loaded'
				? (modelsByRow[key] as { expanded: boolean }).expanded
				: false;
		modelsByRow = {
			...modelsByRow,
			[key]: { phase: 'loaded', result: res.refreshProviderModels, expanded: prevExpanded }
		};
	} catch (e) {
		modelsByRow = {
			...modelsByRow,
			[key]: { phase: 'error', message: e instanceof Error ? e.message : String(e) }
		};
	} finally {
		refreshingRow = { ...refreshingRow, [key]: false };
	}
}

function toggleExpanded(row: ProviderStatus): void {
	const key = rowKey(row);
	const state = modelsByRow[key];
	if (state?.phase !== 'loaded') return;
	modelsByRow = {
		...modelsByRow,
		[key]: { ...state, expanded: !state.expanded }
	};
}

