input.new_string:
function toggleExpanded(row: ProviderStatus): void {
	const key = rowKey(row);
	const state = modelsByRow[key];
	if (state?.phase !== 'loaded') return;
	modelsByRow = {
		...modelsByRow,
		[key]: { ...state, expanded: !state.expanded }
	};
}

function visibleModels(state: ModelsCellState): ProviderModelEntry[] {
	if (state.phase !== 'loaded') return [];
	return state.expanded ? state.result.models : state.result.models.slice(0, INLINE_MODEL_LIMIT);
}

function hiddenCount(state: ModelsCellState): number {
	if (state.phase !== 'loaded') return 0;
	return state.expanded ? 0 : Math.max(0, state.result.models.length - INLINE_MODEL_LIMIT);
}

